class GradientScorer(BaseScorer):
    def __init__(self, model, dataloader, device):
        super().__init__(model, dataloader, device)
        self.gradients = {}

    def head_score(self, module, input, output):
        if hasattr(output, 'requires_grad') and output.requires_grad:
            output.retain_grad()

    def intermediate_score(self, module, input, output):
        if hasattr(output, 'requires_grad') and output.requires_grad:
            output.retain_grad()

    def hidden_score(self, module, input, output):
        if hasattr(output, 'requires_grad') and output.requires_grad:
            output.retain_grad()

    def _collect_grads(self):
        for name, param in self.model.named_parameters():
            if param.grad is not None:
                self.gradients[name] = param.grad.abs().mean().item()
        return self.gradients

class MagnitudeScorer(BaseScorer):
    def __init__(self, model, dataloader, device):
        super().__init__(model, dataloader, device)
        self.magnitudes = {}

    def step(self):
        for name, param in self.model.named_parameters():
            if param.requires_grad:
                self.magnitudes[name] = param.data.abs().mean().item()

    def get_score(self):
        return self.magnitudes

    def save_state(self):
        return self.magnitudes

class RunningSalienceScorer(RunningScorer):
    def __init__(self, model, dataloader, device):
        super().__init__(model, dataloader, device)
        self.module_scores = {}

    def _gather_module_score(self, module, input, output):
        if isinstance(output, torch.Tensor) and output.requires_grad:
            output.retain_grad()
            activation = output.detach().cpu()
            gradient = output.grad.cpu()
            salience = (activation * gradient).abs().sum()
            self.module_scores[module] = salience

    def get_score(self):
        return {k: v.item() for k, v in self.module_scores.items()}

