class L0Module(Module):
    def __init__(self,
                 config, 
                 droprate_init=0.5,
                 temperature=2./3.,
                 lagrangian_warmup=0,
                 start_sparsity=0.0,
                 target_sparsity=0.0,
                 pruning_type="structured_heads+structured_mlp+hidden+layer",
                 magical_number=0.8, # from Wang et al. 2020
                 ):
        super(L0Module, self).__init__()
        self.all_types = ["hidden_z", "intermediate_z", "mlp_z", "head_layer_z", "head_z"]
        self.pruning_type = pruning_type

    def lagrangian_regularization(self):
        # Computes L0 regularization term using loga parameters
        # Sum of expected number of active parameters via concrete distribution
        total_reg = 0
        for loga in self.logas:
            # Expected number of active units: P(z=1) = sigmoid(loga)
            total_reg += torch.sigmoid(loga).sum()
        return total_reg

    def _sample_z(self, loga, training):
        # Samples binary mask via concrete distribution
        if training:
            u = torch.rand_like(loga)
            s = torch.sigmoid((torch.log(u) - torch.log(1 - u) + loga) / self.temperature)
            z = s.clamp(min=1e-5, max=1-1e-5)
            return z
        else:
            return torch.sigmoid(loga).clamp(min=1e-5, max=1-1e-5)

    def get_z_from_zs(self, zs):
        # Returns deterministic binary mask for inference
        return (zs > 0.5).float()

    def cdf_qz(self, x, loga, temperature):
        # CDF of the concrete distribution
        return torch.sigmoid((torch.log(x) - torch.log(1 - x) + loga) / temperature)

    def quantile_concrete(self, q, loga, temperature):
        # Inverse CDF (quantile) of concrete distribution
        return torch.sigmoid((torch.log(q) - torch.log(1 - q) + loga) / temperature)

    def constrain_parameters(self):
        # Constrains loga parameters to avoid numerical instability
        for loga in self.logas:
            loga.data.clamp_(min=-10, max=10)

    def reset_loga(self):
        # Initializes loga parameters with droprate_init
        for loga in self.logas:
            loga.data.fill_(math.log(1 - self.droprate_init) - math.log(self.droprate_init))

    def initialize_parameters(self):
        # Initializes all loga parameters for each pruning type
        self.logas = []
        for t in self.all_types:
            if t in self.pruning_type:
                loga = nn.Parameter(torch.Tensor(self.sizes[t]))
                self.register_parameter(f"loga_{t}", loga)
                self.logas.append(loga)

    def forward(self, training=True):
        # Returns sampled masks for pruning during training, deterministic during eval
        zs = {}
        for t in self.all_types:
            if t in self.pruning_type:
                loga = getattr(self, f"loga_{t}")
                z = self._sample_z(loga, training)
                zs[t] = z
        return zs

