class BasePruner:
    def generate_mask(self, model: PreTrainedModel, sparsity: float) -> Dict[str, torch.Tensor]:
        raise NotImplementedError

class RandomPruner(BasePruner):
    def random_mask(self, tensor: torch.Tensor, sparsity: float) -> torch.Tensor:
        mask = torch.rand_like(tensor) > sparsity
        return mask.float()

class GreedyPruner(BasePruner):
    def greedy_mask(self, tensor: torch.Tensor, sparsity: float) -> torch.Tensor:
        flat_tensor = tensor.abs().flatten()
        k = int(len(flat_tensor) * sparsity)
        threshold = torch.topk(flat_tensor, k, largest=False).values.max()
        mask = (tensor.abs() > threshold).float()
        return mask

class FisherPruner(BasePruner):
    def generate_mask(self, model: PreTrainedModel, sparsity: float) -> Dict[str, torch.Tensor]:
        # Assumes Fisher information scores are precomputed and stored in model's gradients
        masks = {}
        for name, param in model.named_parameters():
            if 'weight' in name and param.grad is not None:
                fisher_score = (param.grad ** 2) * param.data.abs()
                masks[name] = self.greedy_mask(fisher_score, sparsity)
        return masks

class BetterFisherPruner(BasePruner):
    def generate_mask(self, model: PreTrainedModel, sparsity: float) -> Dict[str, torch.Tensor]:
