def calculate_fisher(model, dataloader, device):
    fisher = {}
    for name, param in model.named_parameters():
        if param.requires_grad:
            fisher[name] = torch.zeros_like(param)

    model.train()
    for batch in dataloader:
        batch = {k: v.to(device) for k, v in batch.items()}
        model.zero_grad()
        outputs = model(**batch)
        loss = outputs.loss
        loss.backward()

        for name, param in model.named_parameters():
            if param.grad is not None:
                fisher[name] += param.grad.data.pow(2)

    for name in fisher:
        fisher[name] /= len(dataloader)
    return fisher

def fisher_mask_score(model, dataloader, device, sparsity_target=0.5):
    fisher = calculate_fisher(model, dataloader, device)
    all_scores = []
    for name, score in fisher.items():
        all_scores.append(score.flatten())
    all_scores = torch.cat(all_scores)
    threshold = torch.quantile(all_scores, sparsity_target)

    mask_dict = {}
    for name, score in fisher.items():
        mask_dict[name] = (score >= threshold).float()
    return mask_dict

def sum_fisher_score(fisher_scores):
    total = 0
    for name, score in fisher_scores.items():
        total += score.sum().item()
    return total

