def get_backbone(model):
    model_type = model.base_model_prefix
    backbone = getattr(model, model_type)
    return backbone

def get_encoder(model):
    if hasattr(model, 'encoder'):
        backbone = model
    else:
        backbone = get_backbone(model)
    if hasattr(backbone, 'encoder'):
        return backbone.encoder
    else:
        return None

def get_decoder(model):
    if hasattr(model, 'decoder'):
        backbone = model
    else:
        backbone = get_backbone(model)
    if hasattr(backbone, 'decoder'):
        return backbone.decoder
    else:
        return None

def get_layers(model):
    encoder = get_encoder(model)
    decoder = get_decoder(model)
    layers = []
    if encoder:
        layers.extend(encoder.layer)
    if decoder:
        layers.extend(decoder.layer)
    return layers

def get_mha_qkv(model):
    layers = get_layers(model)
    qkv_modules = []
    for layer in layers:
        if hasattr(layer, 'attention') and hasattr(layer.attention, 'self'):
            qkv_modules.append(layer.attention.self.query)
            qkv_modules.append(layer.attention.self.key)
            qkv_modules.append(layer.attention.self.value)
    return qkv_modules

def get_mha_proj(model):
    layers = get_layers(model)
    proj_modules = []
    for layer in layers:
        if hasattr(layer, 'attention') and hasattr(layer.attention, 'output'):
            proj_modules.append(layer.attention.output.dense)
    return proj_modules

def get_ffn1(model):
    layers = get_layers(model)
    ffn1_modules = []
    for layer in layers:
        if hasattr(layer, 'intermediate'):
            ffn1_modules.append(layer.intermediate.dense)
    return ffn1_modules

def get_ffn2(model):
    layers = get_layers(model)
    ffn2_modules = []
