def closed_form_solver(A, B):
    if B.shape[0] == 1:
        X = B / A[0, 0]
    else:
        # NOTE: for safety, compute matrix inverse on CPU
        X = torch.inverse(A.cpu()).to(A.device) @ B
    return X

